package com.example.productionapi.controller;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1")
public class ProductionApiController {

    private static final Logger log = LoggerFactory.getLogger(ProductionApiController.class);

    @GetMapping("/status")
    public ResponseEntity<String> getStatus() {
        log.info("API Flow: Received GET request for /api/v1/status");
        String statusMessage = "API Service is Up and Running!";
        log.info("Operation Success: getStatus completed successfully. Response: {}", statusMessage);
        return ResponseEntity.ok(statusMessage);
    }

    @GetMapping("/greet")
    public ResponseEntity<String> greetUser(@RequestParam(value = "name", defaultValue = "Guest") String name) {
        log.debug("API Flow: Entering greetUser method with name: {}", name);
        if (name == null || name.trim().isEmpty()) {
            log.warn("API Flow: 'name' parameter was empty or null. Using default 'Guest'.");
            name = "Guest";
        }

        String greeting = String.format("Hello, %s! Welcome to our Production API.", name);
        log.info("Operation Success: Successfully greeted user '{}'.", name);
        return ResponseEntity.ok(greeting);
    }

    @GetMapping("/calculate-sum")
    public ResponseEntity<Integer> calculateSum(@RequestParam("a") int a, @RequestParam("b") int b) {
        log.debug("API Flow: Received request to calculate sum for a={} and b={}", a, b);
        int sum = a + b;
        log.info("Operation Success: Calculated sum of {} and {} is {}.", a, b, sum);
        return ResponseEntity.ok(sum);
    }
}